INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100757, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n/* Divi injects: @media(max-width:640px){.et_pb_section .et_pb_row{padding:0 24px !important}}\n   Specificity 0,2,0. We use .et_pb_row.et_pb_row (0,2,0 doubled = 0,2,0 still, but\n   .et_pb_section prefix pushes us to 0,3,0) to beat it. */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === BLOG POST: SHOP FLOOR MINI-SCHEDULING: WHEN PLANS MEET REALITY === */\n/* Divi section-level overrides — reset padding/margin/width on all sections */\n.et_pb_section { padding: 0 !important; min-height: auto !important; margin: 0 !important; text-align: start !important; }\n.et_pb_section .et_pb_row { max-width: 100% !important; width: 100% !important; padding: 0 !important; margin: 0 auto !important; }\n.et_pb_section .et_pb_column { padding: 0 !important; }\n/* Font smoothing reset */\n.et_pb_section, .et_pb_section * { -webkit-font-smoothing: auto !important; -moz-osx-font-smoothing: auto !important; }\n/* Divi p padding reset */\n.et_pb_section p { padding-bottom: 0 !important; }\n/* Override blog-body h2/h3 line-height from Divi defaults */\n.et_pb_section .blog-body h2, .et_pb_section .article-body h2 { line-height: 1.3 !important; }\n.et_pb_section .blog-body h3, .et_pb_section .article-body h3 { line-height: 1.35 !important; }\n/* Ensure fade-in elements are visible (no JS scroll observer in Divi) */\n.fade-in { opacity: 1 !important; transform: none !important; }\n/* Resolve CSS vars used in styles.css */\n:root { --dw-blue-text: #0369a1; --dw-gray-light: #F5F7FA; --dw-navy: #000864; }\n\n/* Blog base CSS (extracted from styles.css) */\n.blog-hero {\n    background: linear-gradient(135deg, #0f1419 0%, #000432 40%, #000864 100%);\n    padding: 160px 24px 60px;\n    position: relative;\n    overflow: hidden;\n}\n.blog-hero::before {\n    content: \'\';\n    position: absolute;\n    inset: 0;\n    background-image: url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.03\'%3E%3Ccircle cx=\'30\' cy=\'30\' r=\'1.5\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");\n    pointer-events: none;\n}\n.blog-hero-inner {\n    max-width: 800px;\n    margin: 0 auto;\n    position: relative;\n    z-index: 1;\n}\n.blog-back-link {\n    display: inline-flex;\n    align-items: center;\n    gap: 6px;\n    color: rgba(255,255,255,0.85);\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: 15px;\n    font-weight: 500;\n    text-decoration: none;\n    transition: color 0.3s ease;\n}\n.blog-back-link:hover {\n    color: #00AFF0;\n}\n.blog-back-link svg {\n    width: 16px;\n    height: 16px;\n    stroke: currentColor;\n}\n.blog-category-badge {\n    display: inline-block;\n    font-family: \'JetBrains Mono\', monospace;\n    font-size: 11px;\n    font-weight: 500;\n    letter-spacing: 0.1em;\n    text-transform: uppercase;\n    color: #fff;\n    padding: 5px 12px;\n    border-radius: 4px;\n}\n.blog-hero h1 {\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: clamp(28px, 4.5vw, 42px);\n    font-weight: 700;\n    color: #fff;\n    line-height: 1.2;\n    margin-bottom: 20px;\n}\n.blog-meta {\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: 15px;\n    color: rgba(255,255,255,0.85);\n    display: flex;\n    align-items: center;\n    gap: 12px;\n}\n.blog-meta-dot {\n    width: 4px;\n    height: 4px;\n    border-radius: 50%;\n    background: rgba(255,255,255,0.3);\n}\n.blog-body {\n    max-width: 760px;\n    margin: 0 auto;\n    padding: 0 24px;\n}\n.blog-body h2 {\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: 28px;\n    font-weight: 600;\n    color: #000864;\n    margin-top: 56px;\n    margin-bottom: 20px;\n    line-height: 1.3;\n}\n.blog-body h3 {\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: 22px;\n    font-weight: 600;\n    color: #000864;\n    margin-top: 40px;\n    margin-bottom: 16px;\n    line-height: 1.35;\n}\n.blog-body p {\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: 18px;\n    line-height: 1.8;\n    color: #333333;\n    margin-bottom: 24px;\n}\n.blog-body ul, .blog-body ol {\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: 18px;\n    line-height: 1.8;\n    color: #333333;\n    margin-bottom: 24px;\n    padding-left: 24px;\n}\n.blog-body li {\n    margin-bottom: 8px;\n}\n.blog-body strong {\n    color: #000864;\n    font-weight: 600;\n}\n.blog-pullquote {\n    border-left: 4px solid #00AFF0;\n    padding: 8px 0 8px 24px;\n    margin: 40px 0;\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: 20px;\n    font-style: italic;\n    color: #000864;\n    line-height: 1.6;\n}\n.blog-data-card {\n    background: linear-gradient(135deg, #000432 0%, #000864 100%);\n    border-radius: 12px;\n    padding: 40px;\n    margin: 40px 0;\n    text-align: center;\n    position: relative;\n    overflow: hidden;\n}\n.blog-data-card::before {\n    content: \'\';\n    position: absolute;\n    inset: 0;\n    background-image: url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.03\'%3E%3Ccircle cx=\'30\' cy=\'30\' r=\'1.5\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");\n    pointer-events: none;\n}\n.blog-data-card-content {\n    position: relative;\n    z-index: 1;\n}\n.blog-data-number {\n    font-family: \'JetBrains Mono\', monospace;\n    font-size: clamp(32px, 5vw, 48px);\n    font-weight: 500;\n    color: #00AFF0;\n    line-height: 1.2;\n    margin-bottom: 8px;\n}\n.blog-data-arrow {\n    font-size: 32px;\n    color: rgba(255,255,255,0.85);\n    margin: 4px 0;\n}\n.blog-data-label {\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: 16px;\n    color: rgba(255,255,255,0.85);\n    line-height: 1.5;\n    margin-top: 12px;\n}\n.blog-data-inline {\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    gap: 24px;\n    flex-wrap: wrap;\n}\n.blog-highlight {\n    background: #EBF5FF;\n    border-left: 4px solid #00AFF0;\n    border-radius: 0 8px 8px 0;\n    padding: 20px 24px;\n    margin: 32px 0;\n}\n.blog-highlight p {\n    font-size: 16px;\n    line-height: 1.7;\n    color: #000864;\n    margin-bottom: 0;\n}\n.blog-highlight p + p {\n    margin-top: 12px;\n}\n.blog-highlight strong {\n    color: #000432;\n}\n.blog-divider {\n    width: 60px;\n    height: 3px;\n    background: #00AFF0;\n    border: none;\n    margin: 56px 0;\n    border-radius: 2px;\n}\n.article-diagram {\n    max-width: 100%;\n    margin: 48px auto;\n    text-align: center;\n}\n.article-diagram svg {\n    max-width: 100%;\n    height: auto;\n}\n.diagram-caption {\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: 14px;\n    color: #666666;\n    margin-top: 12px;\n    font-style: italic;\n}\n.blog-related {\n    background: #F5F7FA;\n    padding: 80px 24px;\n}\n.blog-related-inner {\n    max-width: 1200px;\n    margin: 0 auto;\n}\n.blog-related h2 {\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: 28px;\n    font-weight: 600;\n    color: #000864;\n    text-align: center;\n    margin-bottom: 48px;\n}\n.blog-related-grid {\n    display: grid;\n    grid-template-columns: repeat(3, 1fr);\n    gap: 24px;\n}\n.blog-related-card {\n    background: #fff;\n    border-radius: 12px;\n    padding: 32px 28px;\n    text-decoration: none;\n    border: 1px solid rgba(37, 59, 80, 0.08);\n    box-shadow: 0 2px 12px rgba(0,0,0,0.06);\n    transition: all 0.3s ease;\n    display: flex;\n    flex-direction: column;\n}\n.blog-related-card:hover {\n    transform: translateY(-4px);\n    box-shadow: 0 8px 24px rgba(0,0,0,0.1);\n}\n.blog-related-card h3 {\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: 18px;\n    font-weight: 600;\n    color: #000864;\n    line-height: 1.4;\n    margin: 0 0 4px;\n}\n.blog-related-card h3 a {\n    color: inherit;\n    text-decoration: none;\n}\n.blog-related-card h3 a:hover {\n    color: #00AFF0;\n}\n.blog-related-meta {\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: 14px;\n    font-weight: 400;\n    color: #666;\n    margin: 0 0 16px;\n}\n.blog-related-excerpt {\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: 14px;\n    line-height: 1.6;\n    color: #333;\n    margin: 0 0 16px;\n    display: -webkit-box;\n    -webkit-line-clamp: 3;\n    -webkit-box-orient: vertical;\n    overflow: hidden;\n    flex-grow: 1;\n}\n.blog-related-readmore {\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: 14px;\n    font-weight: 600;\n    color: #00AFF0;\n    text-decoration: none;\n}\n.blog-related-readmore:hover {\n    text-decoration: underline;\n}\n.blog-cta {\n    background: linear-gradient(135deg, #0f1419 0%, #000432 40%, #000864 100%);\n    padding: 80px 24px;\n    text-align: center;\n    position: relative;\n    overflow: hidden;\n}\n.blog-cta::before {\n    content: \'\';\n    position: absolute;\n    inset: 0;\n    background-image: url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.03\'%3E%3Ccircle cx=\'30\' cy=\'30\' r=\'1.5\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");\n    pointer-events: none;\n}\n.blog-cta-inner {\n    max-width: 640px;\n    margin: 0 auto;\n    position: relative;\n    z-index: 1;\n}\n.blog-cta h2 {\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: clamp(24px, 4vw, 36px);\n    font-weight: 700;\n    color: #fff;\n    margin-bottom: 16px;\n    line-height: 1.25;\n}\n.blog-cta p {\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: 18px;\n    color: rgba(255,255,255,0.85);\n    line-height: 1.7;\n    margin-bottom: 32px;\n}\n.blog-cta-btn {\n    display: inline-flex;\n    align-items: center;\n    gap: 10px;\n    background: #00AFF0;\n    color: #fff;\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: 16px;\n    font-weight: 600;\n    padding: 16px 36px;\n    border-radius: 8px;\n    text-decoration: none;\n    transition: all 0.3s ease;\n}\n.blog-cta-btn:hover {\n    background: #2b7bc4;\n    transform: translateY(-2px);\n    box-shadow: 0 8px 24px rgba(0, 175, 240, 0.3);\n}\n.blog-cta-btn svg {\n    width: 18px;\n    height: 18px;\n    stroke: currentColor;\n}\n.fade-in {\n    opacity: 0;\n    transform: translateY(16px);\n    transition: opacity 0.2s ease, transform 0.2s ease;\n}\n.fade-in.visible {\n    opacity: 1;\n    transform: translateY(0);\n}\n.fade-in.no-delay {\n    opacity: 1;\n    transform: none;\n    transition: none;\n}\n    .fade-in {\n        opacity: 1;\n        transform: none;\n        transition: none;\n    }\n    .blog-hero {\n        padding: 140px 20px 48px;\n    }\n    .blog-hero h1 {\n        font-size: 26px;\n    }\n    .blog-back-link {\n        min-height: 44px;\n        padding: 8px 0;\n    }\n    .blog-body {\n        padding: 0 20px;\n    }\n    .blog-body h2 {\n        font-size: 24px;\n        margin-top: 44px;\n    }\n    .blog-body p,\n    .blog-body ul,\n    .blog-body ol {\n        font-size: 17px;\n    }\n    .blog-pullquote {\n        font-size: 18px;\n        padding-left: 20px;\n        margin: 32px 0;\n    }\n    .blog-data-card {\n        padding: 28px 20px;\n    }\n    .blog-data-number {\n        font-size: 28px;\n    }\n    .blog-data-inline {\n        flex-direction: column;\n        gap: 8px;\n    }\n    .blog-related-grid {\n        grid-template-columns: 1fr;\n        gap: 16px;\n    }\n    .blog-related-card {\n        padding: 24px 20px;\n    }\n    .blog-cta {\n        padding: 60px 20px;\n    }\n.blog-hero-inner {\n    max-width: 1200px;\n    margin: 0 auto;\n    padding: 0 24px;\n    position: relative;\n    z-index: 2;\n    animation: slide-up 0.8s ease-out;\n}\n.blog-data-number--success {\n    color: var(--event-color, #22C55E);\n}\n.blog-data-label--spaced {\n    margin-top: 12px;\n}\n.dw-section {\n    padding: 100px 80px;\n}\n.dw-section--white {\n    background: #ffffff;\n}\n.dw-section--gray {\n    background: #F5F7FA;\n}\n.dw-section--dark {\n    background: linear-gradient(135deg, #000864 0%, #1e3a5f 100%);\n    color: #ffffff;\n}\n.dw-section--blue {\n    background: linear-gradient(135deg, #00AFF0 0%, #0ea5e9 50%, #0284c7 100%);\n    color: #ffffff;\n    position: relative;\n}\n.dw-section--blue::before {\n    content: \'\';\n    position: absolute;\n    top: 0;\n    left: 0;\n    right: 0;\n    bottom: 0;\n    background: radial-gradient(ellipse at 20% 30%, rgba(255,255,255,0.15) 0%, transparent 50%);\n    pointer-events: none;\n}\n    .dw-section {\n        padding: 60px 40px;\n    }\n    .dw-section {\n        padding: 48px 24px;\n    }\n\n.blog-category-badge { background: #644CE6; }\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}');

